"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useAuthStore } from "@/stores/authStore";
import { useTableStore } from "@/stores/tableStore";
import { getOrders, cancelOrderItem, createPayment, requestCashPayment, getMySessionInfo, payForTable } from "@/lib/api";
import { Header } from "@/components/layout/Header";
import { BottomNav } from "@/components/layout/BottomNav";
import { Button } from "@/components/ui/Button";
import { Badge } from "@/components/ui/Badge";
import { Icon } from "@/components/ui/Icon";
import { useToast } from "@/components/ui/Toast";
import type { OrderStatus, OrderItemStatus, Order, GuestSessionInfo, OrderType } from "@/types";
import { normalizeOrderStatus, normalizeItemStatus, normalizeOrderType } from "@/types";

const statusConfig: Record<
  OrderStatus,
  { label: string; variant: "default" | "success" | "warning" | "error" | "primary" }
> = {
  Pending: { label: "Ожидает", variant: "warning" },
  Confirmed: { label: "Подтверждён", variant: "primary" },
  Completed: { label: "Завершён", variant: "default" },
  Cancelled: { label: "Отменён", variant: "error" },
};

const itemStatusConfig: Record<
  OrderItemStatus,
  { label: string; variant: "default" | "success" | "warning" | "error" | "primary" }
> = {
  Pending: { label: "Новое", variant: "warning" },
  Active: { label: "Принято", variant: "success" },
  Cancelled: { label: "Отменено", variant: "error" },
};

export default function OrdersPage() {
  const router = useRouter();
  const { isAuthenticated } = useAuthStore();
  const { onlinePaymentAvailable: tableOnlinePayment } = useTableStore();
  const queryClient = useQueryClient();
  const { showToast } = useToast();
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [cancellingItemId, setCancellingItemId] = useState<string | null>(null);
  const [processingPayment, setProcessingPayment] = useState<string | null>(null);
  const [paymentModalOrder, setPaymentModalOrder] = useState<Order | null>(null);
  const [sessionInfo, setSessionInfo] = useState<GuestSessionInfo | null>(null);
  const [loadingSessionInfo, setLoadingSessionInfo] = useState(false);

  const { data: orders = [], isLoading } = useQuery({
    queryKey: ["orders"],
    queryFn: getOrders,
    enabled: isAuthenticated,
    refetchInterval: 10000, // Auto-refresh every 10 seconds
  });

  const cancelItemMutation = useMutation({
    mutationFn: ({ orderId, itemId }: { orderId: string; itemId: string }) =>
      cancelOrderItem(orderId, itemId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["orders"] });
      setSelectedOrder(null);
    },
    onSettled: () => {
      setCancellingItemId(null);
    },
  });

  const handleCancelItem = (orderId: string, itemId: string) => {
    if (confirm("Вы уверены, что хотите отменить это блюдо?")) {
      setCancellingItemId(itemId);
      cancelItemMutation.mutate({ orderId, itemId });
    }
  };

  // Handle cash payment
  const handleCashPayment = async (order: Order) => {
    setProcessingPayment(order.id);
    try {
      await requestCashPayment(order.id);
      showToast("Официант скоро подойдёт для оплаты", "success");
      queryClient.invalidateQueries({ queryKey: ["orders"] });
    } catch (error) {
      showToast("Ошибка запроса оплаты", "error");
    } finally {
      setProcessingPayment(null);
    }
  };

  // Fetch session info when opening payment modal
  const openPaymentModal = async (order: Order) => {
    setPaymentModalOrder(order);
    setLoadingSessionInfo(true);
    try {
      const info = await getMySessionInfo(order.tableId);
      setSessionInfo(info);
    } catch {
      setSessionInfo(null);
    } finally {
      setLoadingSessionInfo(false);
    }
  };

  // Handle pay for table (cash)
  const handlePayForTableCash = async () => {
    if (!sessionInfo || !paymentModalOrder) return;
    setProcessingPayment('table-cash');
    try {
      await payForTable(sessionInfo.sessionId, 'cash');
      showToast("Официант скоро подойдёт для оплаты за весь стол", "success");
      queryClient.invalidateQueries({ queryKey: ["orders"] });
      setPaymentModalOrder(null);
      setSessionInfo(null);
    } catch (error) {
      showToast("Ошибка запроса оплаты", "error");
    } finally {
      setProcessingPayment(null);
    }
  };

  // Handle pay for table (online)
  const handlePayForTableOnline = async () => {
    if (!sessionInfo || !paymentModalOrder) return;
    setProcessingPayment('table-online');
    try {
      const result = await payForTable(sessionInfo.sessionId, 'online');
      if (result.paymentLink) {
        window.location.href = result.paymentLink;
      } else {
        showToast("Онлайн оплата недоступна", "error");
      }
    } catch (error) {
      showToast("Ошибка создания платежа", "error");
    } finally {
      setProcessingPayment(null);
    }
  };

  // Handle DC card payment
  const handleDcPayment = async (order: Order) => {
    // If there's a payment link, use it
    if (order.paymentLink) {
      const finalLink = order.paymentLink.replace('{amount}', order.total.toString());
      window.location.href = finalLink;
      return;
    }

    setProcessingPayment(order.id);
    try {
      const baseUrl = window.location.origin;
      const paymentData = await createPayment({
        orderId: order.id,
        approveUrl: `${baseUrl}/payment/callback?status=success&orderId=${order.id}`,
        declineUrl: `${baseUrl}/payment/callback?status=failed&orderId=${order.id}`,
        cancelUrl: `${baseUrl}/payment/callback?status=cancelled&orderId=${order.id}`,
      });

      // Create and submit form
      const form = document.createElement("form");
      form.method = "POST";
      form.action = paymentData.formUrl;

      Object.entries(paymentData.formFields).forEach(([key, value]) => {
        const input = document.createElement("input");
        input.type = "hidden";
        input.name = key;
        input.value = value;
        form.appendChild(input);
      });

      document.body.appendChild(form);
      form.submit();
    } catch (error) {
      showToast("Ошибка создания платежа", "error");
      setProcessingPayment(null);
    }
  };

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat("ru-RU").format(price);
  };

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleString("ru-RU", {
      day: "numeric",
      month: "short",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-background pb-20">
        <Header title="Мои заказы" />
        <div className="flex flex-col items-center justify-center py-20 px-4">
          <div className="w-24 h-24 rounded-full bg-orange-50 flex items-center justify-center mb-6">
            <Icon name="lock" size={48} className="text-orange-400" />
          </div>
          <h2 className="text-xl font-bold text-foreground mb-2">
            Требуется авторизация
          </h2>
          <p className="text-muted text-center mb-6">
            Чтобы просмотреть историю заказов, оформите заказ
          </p>
          <Button onClick={() => router.push("/menu")}>Перейти в меню</Button>
        </div>
        <BottomNav />
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background pb-20">
        <Header title="Мои заказы" />
        <div className="p-4 space-y-4">
          {Array.from({ length: 3 }).map((_, i) => (
            <div key={i} className="bg-white rounded-xl p-4 animate-pulse border border-border">
              <div className="h-4 bg-gray-200 rounded w-1/3 mb-3" />
              <div className="h-3 bg-gray-200 rounded w-2/3 mb-2" />
              <div className="h-3 bg-gray-200 rounded w-1/2" />
            </div>
          ))}
        </div>
        <BottomNav />
      </div>
    );
  }

  if (orders.length === 0) {
    return (
      <div className="min-h-screen bg-background pb-20">
        <Header title="Мои заказы" />
        <div className="flex flex-col items-center justify-center py-20 px-4">
          <div className="w-24 h-24 rounded-full bg-orange-50 flex items-center justify-center mb-6">
            <Icon name="receipt_long" size={48} className="text-orange-400" />
          </div>
          <h2 className="text-xl font-bold text-foreground mb-2">Нет заказов</h2>
          <p className="text-muted text-center mb-6">
            Ваши заказы появятся здесь после оформления
          </p>
          <Button onClick={() => router.push("/menu")}>Перейти в меню</Button>
        </div>
        <BottomNav />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background pb-20">
      <Header title="Мои заказы" />

      <div className="p-4 space-y-4">
        {orders.map((order) => {
          if (!order) return null;
          const normalizedStatus = normalizeOrderStatus(order.status);
          const status = statusConfig[normalizedStatus] || { label: String(order.status) || "Неизвестно", variant: "default" as const };
          const showPaymentButtons = !order.isPaid && normalizedStatus !== "Cancelled";
          const hasOnlinePayment = order.onlinePaymentAvailable || tableOnlinePayment;

          const orderType = order.orderType ? normalizeOrderType(order.orderType) : "DineIn";
          const isDelivery = orderType === "Delivery";
          const isTakeaway = orderType === "Takeaway";

          return (
            <div
              key={order.id}
              className="bg-white rounded-xl p-4 space-y-3 border border-border shadow-sm"
            >
              {/* Order header */}
              <div
                className="flex items-center justify-between cursor-pointer"
                onClick={() => setSelectedOrder(order)}
              >
                <div>
                  <p className="text-muted text-sm">
                    {formatDate(order.createdAt)}
                  </p>
                  <div className="flex items-center gap-2">
                    {isDelivery && (
                      <Icon name="delivery_dining" size={18} className="text-orange-500" />
                    )}
                    {isTakeaway && (
                      <Icon name="takeout_dining" size={18} className="text-green-500" />
                    )}
                    <p className="text-foreground font-semibold">
                      {isDelivery
                        ? "Доставка"
                        : isTakeaway
                        ? "Самовывоз"
                        : order.tableName || `Стол #${order.tableNumber}`}
                    </p>
                  </div>
                  {order.restaurantName && (
                    <p className="text-xs text-primary">{order.restaurantName}</p>
                  )}
                  {isDelivery && order.deliveryAddress && (
                    <p className="text-xs text-muted mt-1 flex items-center gap-1">
                      <Icon name="location_on" size={12} />
                      {order.deliveryAddress}
                    </p>
                  )}
                  {(isDelivery || isTakeaway) && order.customerName && (
                    <p className="text-xs text-muted flex items-center gap-1">
                      <Icon name="person" size={12} />
                      {order.customerName}
                    </p>
                  )}
                </div>
                <div className="flex flex-col items-end gap-1">
                  <Badge variant={status.variant} size="md">
                    {status.label}
                  </Badge>
                  {order.isPaid && (
                    <Badge variant="success" size="sm">
                      Оплачено
                    </Badge>
                  )}
                  {order.hasPendingItems && (
                    <Badge variant="warning" size="sm">
                      Новые блюда
                    </Badge>
                  )}
                  {isDelivery && (
                    <Badge variant="primary" size="sm">
                      Доставка
                    </Badge>
                  )}
                  {isTakeaway && (
                    <Badge variant="default" size="sm">
                      Самовывоз
                    </Badge>
                  )}
                </div>
              </div>

              {/* Order items preview */}
              <div
                className="border-t border-border pt-3 space-y-1 cursor-pointer"
                onClick={() => setSelectedOrder(order)}
              >
                {(order.items || []).slice(0, 3).map((item) => {
                  if (!item) return null;
                  const normalizedItemStatus = normalizeItemStatus(item.status);
                  const itemStatus = itemStatusConfig[normalizedItemStatus] || { label: "Активно", variant: "success" as const };
                  const isCancelled = normalizedItemStatus === "Cancelled";
                  return (
                    <div
                      key={item.id}
                      className={`flex justify-between text-sm ${isCancelled ? "opacity-50" : ""}`}
                    >
                      <span className={`text-muted ${isCancelled ? "line-through" : ""}`}>
                        {item.productName} x{item.quantity}
                        <span className={`ml-2 text-xs px-1 rounded ${
                          normalizedItemStatus === "Pending" ? "bg-orange-100 text-orange-600" :
                          normalizedItemStatus === "Cancelled" ? "bg-red-100 text-red-600" :
                          "bg-green-100 text-green-600"
                        }`}>
                          {itemStatus.label}
                        </span>
                      </span>
                      <span className={`text-foreground ${isCancelled ? "line-through" : ""}`}>
                        {formatPrice(item.totalPrice)} TJS
                      </span>
                    </div>
                  );
                })}
                {(order.items || []).length > 3 && (
                  <p className="text-sm text-muted">+{order.items.length - 3} ещё...</p>
                )}
              </div>

              {/* Order total */}
              <div className="flex items-center justify-between pt-2 border-t border-border">
                <div>
                  <span className="text-muted">Итого</span>
                  {isDelivery && order.deliveryFee && order.deliveryFee > 0 && (
                    <span className="text-xs text-muted ml-2">
                      (вкл. доставка {formatPrice(order.deliveryFee)})
                    </span>
                  )}
                </div>
                <span className="text-orange-500 font-bold text-lg">
                  {formatPrice(order.total)} TJS
                </span>
              </div>

              {/* Action buttons for unpaid orders */}
              {showPaymentButtons && (
                <div className={`pt-3 border-t border-border grid gap-2 ${
                  !isDelivery && !isTakeaway ? "grid-cols-2" : "grid-cols-1"
                }`}>
                  {/* Add more button - only for dine-in */}
                  {!isDelivery && !isTakeaway && (
                    <Button
                      variant="outline"
                      onClick={() => router.push("/menu")}
                    >
                      <Icon name="add" size={18} className="mr-1" />
                      Добавить
                    </Button>
                  )}

                  {/* Pay button */}
                  <Button
                    onClick={() => openPaymentModal(order)}
                    disabled={processingPayment === order.id}
                  >
                    <Icon name="payments" size={18} className="mr-1" />
                    Оплатить
                  </Button>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Payment method modal */}
      {paymentModalOrder && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50" onClick={() => { setPaymentModalOrder(null); setSessionInfo(null); }}>
          <div className="bg-white rounded-xl p-6 w-full max-w-sm mx-4" onClick={(e) => e.stopPropagation()}>
            <h3 className="text-lg font-bold mb-4 text-center">Способ оплаты</h3>

            {/* Session info banner */}
            {loadingSessionInfo ? (
              <div className="mb-4 p-3 bg-gray-50 rounded-lg animate-pulse">
                <div className="h-4 bg-gray-200 rounded w-1/2 mb-2"></div>
                <div className="h-3 bg-gray-200 rounded w-3/4"></div>
              </div>
            ) : sessionInfo && sessionInfo.guestCount > 1 && (
              <div className="mb-4 space-y-2">
                {/* Header with guest count */}
                <div className="p-3 bg-blue-50 rounded-lg border border-blue-100">
                  <div className="flex items-center justify-between mb-1">
                    <div className="flex items-center gap-2">
                      <Icon name="group" size={18} className="text-blue-500" />
                      <span className="text-sm font-medium text-blue-700">
                        За столом {sessionInfo.guestCount} {sessionInfo.guestCount === 1 ? 'гость' : sessionInfo.guestCount < 5 ? 'гостя' : 'гостей'}
                      </span>
                    </div>
                  </div>
                  <div className="text-xs text-blue-600 space-y-0.5">
                    <div className="flex justify-between">
                      <span>Сумма заказов:</span>
                      <span>{formatPrice(sessionInfo.tableSubtotal)} TJS</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Обслуживание ({sessionInfo.serviceFeePercent}%):</span>
                      <span>{formatPrice(sessionInfo.tableServiceFee)} TJS</span>
                    </div>
                    <div className="flex justify-between font-bold text-blue-700 pt-1 border-t border-blue-200">
                      <span>Итого за стол:</span>
                      <span>{formatPrice(sessionInfo.tableTotal)} TJS</span>
                    </div>
                  </div>
                </div>

                {/* My total */}
                <div className="p-3 bg-green-50 rounded-lg border border-green-100">
                  <div className="text-xs text-green-600 space-y-0.5">
                    <div className="flex justify-between">
                      <span>Мои заказы:</span>
                      <span>{formatPrice(sessionInfo.myOrderSubtotal)} TJS</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Моя доля обслуживания:</span>
                      <span>{formatPrice(sessionInfo.myServiceFeeShare)} TJS</span>
                    </div>
                    <div className="flex justify-between font-bold text-green-700 pt-1 border-t border-green-200">
                      <span>Мой итого:</span>
                      <span>{formatPrice(sessionInfo.myTotal)} TJS</span>
                    </div>
                  </div>
                </div>

                {/* My orders list */}
                {sessionInfo.myOrders.length > 0 && (
                  <div className="space-y-1">
                    <p className="text-xs text-muted px-1">Мои заказы:</p>
                    {sessionInfo.myOrders.map((order) => (
                      <div key={order.orderId} className="flex items-center justify-between p-2 bg-green-50 rounded-lg border border-green-200">
                        <div className="flex items-center gap-2">
                          <span className="text-xs px-1.5 py-0.5 bg-green-500 text-white rounded font-medium">МОЙ</span>
                          <span className="text-sm text-gray-600">{order.itemsPreview}</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <div className="text-right">
                            <span className="text-sm font-semibold">{formatPrice(order.total)} TJS</span>
                            <p className="text-xs text-gray-400">{formatPrice(order.subtotal)} + {formatPrice(order.serviceFeeShare)}</p>
                          </div>
                          {order.isPaid && <Icon name="check_circle" size={16} className="text-green-500" />}
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {/* Other guests' orders */}
                {sessionInfo.otherOrders.length > 0 && (
                  <div className="space-y-1">
                    <p className="text-xs text-muted px-1">Заказы других гостей:</p>
                    {sessionInfo.otherOrders.map((order) => (
                      <div key={order.orderId} className="flex items-center justify-between p-2 bg-gray-50 rounded-lg border border-gray-200">
                        <div className="flex items-center gap-2">
                          <Icon name="person" size={16} className="text-gray-400" />
                          <span className="text-sm text-gray-500">{order.itemsPreview}</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <span className="text-sm text-gray-600">{formatPrice(order.total)} TJS</span>
                          {order.isPaid && <Icon name="check_circle" size={16} className="text-green-500" />}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* My order section */}
            <div className="mb-4">
              <p className="text-sm text-muted mb-2">
                Мой заказ
                {sessionInfo && sessionInfo.guestCount > 1 && (
                  <span className="text-xs text-gray-400 ml-1">
                    ({formatPrice(sessionInfo.myOrderSubtotal)} + {formatPrice(sessionInfo.myServiceFeeShare)} обсл.)
                  </span>
                )}
              </p>
              <div className="grid grid-cols-2 gap-3">
                {/* Cash payment button */}
                <button
                  onClick={() => {
                    handleCashPayment(paymentModalOrder);
                    setPaymentModalOrder(null);
                    setSessionInfo(null);
                  }}
                  disabled={!!processingPayment}
                  className="flex flex-col items-center p-4 rounded-xl
                             bg-orange-50 border-2 border-orange-200
                             hover:border-orange-500 hover:bg-orange-100
                             transition-all disabled:opacity-50"
                >
                  <Icon name="payments" size={32} className="text-orange-500 mb-2" />
                  <span className="font-semibold text-orange-600">Наличными</span>
                  <span className="text-xs text-orange-500/70">
                    {sessionInfo && sessionInfo.guestCount > 1
                      ? formatPrice(sessionInfo.myTotal)
                      : formatPrice(paymentModalOrder.total)} TJS
                  </span>
                </button>

                {/* DC card payment button */}
                {(paymentModalOrder.onlinePaymentAvailable || tableOnlinePayment) && (
                  <button
                    onClick={() => handleDcPayment(paymentModalOrder)}
                    disabled={!!processingPayment}
                    className="flex flex-col items-center p-4 rounded-xl
                               bg-green-50 border-2 border-green-200
                               hover:border-green-500 hover:bg-green-100
                               transition-all disabled:opacity-50"
                  >
                    <Icon name="credit_card" size={32} className="text-green-500 mb-2" />
                    <span className="font-semibold text-green-600">Картой DC</span>
                    <span className="text-xs text-green-500/70">
                      {sessionInfo && sessionInfo.guestCount > 1
                        ? formatPrice(sessionInfo.myTotal)
                        : formatPrice(paymentModalOrder.total)} TJS
                    </span>
                  </button>
                )}
              </div>
            </div>

            {/* Pay for table section - only show if multiple guests and there's unpaid amount */}
            {sessionInfo && sessionInfo.guestCount > 1 && sessionInfo.tableUnpaidAmount > 0 && (
              <div className="border-t border-border pt-4">
                <p className="text-sm text-muted mb-2">Оплатить за весь стол</p>
                <div className="grid grid-cols-2 gap-3">
                  {/* Cash for table */}
                  <button
                    onClick={handlePayForTableCash}
                    disabled={!!processingPayment}
                    className="flex flex-col items-center p-4 rounded-xl
                               bg-purple-50 border-2 border-purple-200
                               hover:border-purple-500 hover:bg-purple-100
                               transition-all disabled:opacity-50"
                  >
                    <Icon name="groups" size={32} className="text-purple-500 mb-2" />
                    <span className="font-semibold text-purple-600">Наличными</span>
                    <span className="text-xs text-purple-500/70">{formatPrice(sessionInfo.tableUnpaidAmount)} TJS</span>
                  </button>

                  {/* Online for table */}
                  {(paymentModalOrder.onlinePaymentAvailable || tableOnlinePayment) && (
                    <button
                      onClick={handlePayForTableOnline}
                      disabled={!!processingPayment}
                      className="flex flex-col items-center p-4 rounded-xl
                                 bg-indigo-50 border-2 border-indigo-200
                                 hover:border-indigo-500 hover:bg-indigo-100
                                 transition-all disabled:opacity-50"
                    >
                      <Icon name="credit_score" size={32} className="text-indigo-500 mb-2" />
                      <span className="font-semibold text-indigo-600">Картой DC</span>
                      <span className="text-xs text-indigo-500/70">{formatPrice(sessionInfo.tableUnpaidAmount)} TJS</span>
                    </button>
                  )}
                </div>
              </div>
            )}

            <Button
              variant="secondary"
              className="w-full mt-4"
              onClick={() => { setPaymentModalOrder(null); setSessionInfo(null); }}
            >
              Отмена
            </Button>
          </div>
        </div>
      )}

      {/* Order details modal */}
      {selectedOrder && (
        <div className="fixed inset-0 bg-black/50 flex items-end justify-center z-50" onClick={() => setSelectedOrder(null)}>
          <div
            className="bg-white rounded-t-2xl w-full max-h-[85vh] overflow-y-auto"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="sticky top-0 bg-white p-4 border-b border-border">
              <div className="w-12 h-1 bg-gray-300 rounded-full mx-auto mb-4" />
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-lg font-bold text-foreground">
                    {selectedOrder.tableName || `Стол #${selectedOrder.tableNumber}`}
                  </h2>
                  {selectedOrder.restaurantName && (
                    <p className="text-sm text-primary">{selectedOrder.restaurantName}</p>
                  )}
                  <p className="text-sm text-muted">{formatDate(selectedOrder.createdAt)}</p>
                </div>
                <div className="flex flex-col items-end gap-1">
                  <Badge variant={statusConfig[normalizeOrderStatus(selectedOrder.status)]?.variant || "default"}>
                    {statusConfig[normalizeOrderStatus(selectedOrder.status)]?.label || String(selectedOrder.status)}
                  </Badge>
                  {selectedOrder.isPaid && (
                    <Badge variant="success" size="sm">
                      Оплачено
                    </Badge>
                  )}
                </div>
              </div>
            </div>

            <div className="p-4 space-y-4">
              <h3 className="font-semibold text-foreground">Позиции заказа</h3>
              {(selectedOrder.items || []).map((item) => {
                if (!item) return null;
                const normalizedItemStatus = normalizeItemStatus(item.status);
                const normalizedOrderStatus = normalizeOrderStatus(selectedOrder.status);
                const isCancelled = normalizedItemStatus === "Cancelled";
                const isPending = normalizedItemStatus === "Pending";
                const canCancel = (isPending || normalizedOrderStatus === "Pending") && !isCancelled;

                return (
                  <div
                    key={item.id}
                    className={`p-3 rounded-lg border ${
                      isCancelled ? "bg-red-50 border-red-200 opacity-60" :
                      isPending ? "bg-orange-50 border-orange-200" :
                      "bg-white border-border"
                    }`}
                  >
                    <div className="flex justify-between items-start">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 flex-wrap">
                          <span className={`font-medium ${isCancelled ? "line-through text-gray-400" : "text-foreground"}`}>
                            {item.productName}
                          </span>
                          <span className={`text-xs px-2 py-0.5 rounded-full ${
                            isCancelled ? "bg-red-100 text-red-600" :
                            isPending ? "bg-orange-100 text-orange-600" :
                            "bg-green-100 text-green-600"
                          }`}>
                            {itemStatusConfig[normalizedItemStatus]?.label || "Активно"}
                          </span>
                        </div>
                        {item.sizeName && (
                          <p className="text-sm text-muted">{item.sizeName}</p>
                        )}
                        {item.selectedAddons && item.selectedAddons.length > 0 && (
                          <p className="text-sm text-muted">+ {item.selectedAddons.join(", ")}</p>
                        )}
                        <p className="text-sm text-muted">
                          {formatPrice(item.unitPrice)} TJS x {item.quantity}
                        </p>
                        {item.cancelReason && (
                          <p className="text-xs text-red-500 mt-1">Причина: {item.cancelReason}</p>
                        )}
                      </div>
                      <div className="flex items-center gap-2">
                        <span className={`font-semibold ${isCancelled ? "line-through text-gray-400" : "text-foreground"}`}>
                          {formatPrice(item.totalPrice)} TJS
                        </span>
                        {canCancel && (
                          <button
                            onClick={() => handleCancelItem(selectedOrder.id, item.id)}
                            disabled={cancellingItemId === item.id}
                            className="p-2 text-red-500 hover:bg-red-100 rounded-lg disabled:opacity-50"
                          >
                            <Icon name="close" size={18} />
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}

              {/* Order totals */}
              <div className="border-t border-border pt-4 space-y-2">
                <div className="flex justify-between text-muted">
                  <span>Подитог</span>
                  <span>{formatPrice(selectedOrder.subtotal)} TJS</span>
                </div>
                <div className="flex justify-between text-muted">
                  <span>Обслуживание (10%)</span>
                  <span>{formatPrice(selectedOrder.serviceFee)} TJS</span>
                </div>
                <div className="flex justify-between font-bold text-lg text-foreground">
                  <span>Итого</span>
                  <span className="text-orange-500">{formatPrice(selectedOrder.total)} TJS</span>
                </div>
              </div>

              {/* Action buttons in modal */}
              {normalizeOrderStatus(selectedOrder.status) !== "Completed" && normalizeOrderStatus(selectedOrder.status) !== "Cancelled" && (
                <div className="grid grid-cols-2 gap-2">
                  {/* Add more items button */}
                  <Button
                    onClick={() => router.push("/menu")}
                    variant="outline"
                  >
                    <Icon name="add" size={18} className="mr-1" />
                    Добавить
                  </Button>

                  {/* Pay button */}
                  {!selectedOrder.isPaid && (
                    <Button
                      onClick={() => {
                        openPaymentModal(selectedOrder);
                        setSelectedOrder(null);
                      }}
                      disabled={processingPayment === selectedOrder.id}
                    >
                      <Icon name="payments" size={18} className="mr-1" />
                      Оплатить
                    </Button>
                  )}
                </div>
              )}

              <Button
                onClick={() => setSelectedOrder(null)}
                variant="secondary"
                className="w-full"
              >
                Закрыть
              </Button>
            </div>
          </div>
        </div>
      )}

      <BottomNav />
    </div>
  );
}
